features.snippet:
module top (input logic clk, input logic rst);
  logic q;
  // clock signal fed as data instead of through the clock port
  always_ff @(posedge clk or posedge rst) begin
    if (rst) q <= 1'b0;
    else     q <= clk;  // clock used as data operand
  end
endmodule

typedef struct packed {
  logic [3:0] field_a;
  logic [3:0] field_b;
} my_struct_t;

module top (input logic clk, input my_struct_t d_in);
  my_struct_t reg_val;
  always_ff @(posedge clk)
    reg_val <= d_in;
endmodule
